import std/strutils
import atcoder/extra/numeric/float128

proc emit(
    index: int;
    aHigh, aLow, bHigh, bLow: uint64;
) =
  let
    a = fromBits(aHigh, aLow)
    b = fromBits(bHigh, bLow)
    negBits = toBits(-a)
    addBits = toBits(a + b)
    subBits = toBits(a - b)

  echo "NEG\t", index, "\t",
    toHex(aHigh, 16), "\t",
    toHex(aLow, 16), "\t",
    toHex(negBits.high, 16), "\t",
    toHex(negBits.low, 16)

  echo "ADD\t", index, "\t",
    toHex(aHigh, 16), "\t",
    toHex(aLow, 16), "\t",
    toHex(bHigh, 16), "\t",
    toHex(bLow, 16), "\t",
    toHex(addBits.high, 16), "\t",
    toHex(addBits.low, 16)

  echo "SUB\t", index, "\t",
    toHex(aHigh, 16), "\t",
    toHex(aLow, 16), "\t",
    toHex(bHigh, 16), "\t",
    toHex(bLow, 16), "\t",
    toHex(subBits.high, 16), "\t",
    toHex(subBits.low, 16)

